  6→	let terminalEl: HTMLDivElement;
  7→	let ws: WebSocket | null = null;
  8→	let terminalInstance: { dispose(): void } | null = null;
  9→
 10→	onMount(() => {
 11→		// Capture cleanup functions set up by the async initialiser below
 12→		let resizeCleanup: (() => void) | undefined;
 13→		let dataCleanup: (() => void) | undefined;
 14→		let termCleanup: (() => void) | undefined;
 15→
 16→		(async (): Promise<void> => {
 17→			const { Terminal } = await import('@xterm/xterm');
 18→			const { FitAddon } = await import('@xterm/addon-fit');
 19→
 20→			const terminal = new Terminal({
 21→				theme: {
 22→					background: '#0f1117',
 23→					foreground: '#e2e8f0',
 24→					cursor: '#6366f1',
 25→					black: '#1a1d27',
 26→					red: '#f87171',
 27→					green: '#4ade80',
 28→					yellow: '#facc15',
 29→					blue: '#60a5fa',
 30→					magenta: '#c084fc',
 31→					cyan: '#22d3ee',
 32→					white: '#e2e8f0'
 33→				},
 34→				fontFamily: "'JetBrains Mono', 'Menlo', 'Monaco', 'Courier New', monospace",
 35→				fontSize: 14,
 36→				lineHeight: 1.4,
 37→				cursorBlink: true
 38→			});
 39→
 40→			terminalInstance = terminal;
 41→			termCleanup = (): void => terminal.dispose();
 42→
 43→			const fitAddon = new FitAddon();
 44→			terminal.loadAddon(fitAddon);
 45→			terminal.open(terminalEl);
 46→			fitAddon.fit();
 47→
 48→			ws = new WebSocket(`/ws/terminal/${sessionId}`);
 49→
 50→			ws.onmessage = (event: MessageEvent): void => {
 51→				try {
 52→					const msg = JSON.parse(event.data as string) as { type: string; data?: string };
 53→					if (msg.type === 'output' && msg.data) {
 54→						terminal.write(msg.data);
 55→					}
 56→				} catch {
 57→					// ignore malformed messages
 58→				}
 59→			};
 60→
 61→			ws.onerror = (): void => {
 62→				terminal.write('\r\n\x1b[31m[Connection error]\x1b[0m\r\n');
 63→			};
 64→
 65→			ws.onclose = (): void => {
 66→				terminal.write('\r\n\x1b[33m[Disconnected]\x1b[0m\r\n');
 67→			};
 68→
 69→			const { dispose: disposeData } = terminal.onData((data: string): void => {
 70→				if (ws?.readyState === WebSocket.OPEN) {
 71→					ws.send(JSON.stringify({ type: 'input', data }));
 72→				}
 73→			});
 74→			dataCleanup = (): void => disposeData();
 75→
 76→			const resizeObserver = new ResizeObserver((): void => {
 77→				fitAddon.fit();
 78→				if (ws?.readyState === WebSocket.OPEN) {
 79→					ws.send(JSON.stringify({ type: 'resize', cols: terminal.cols, rows: terminal.rows }));
 80→				}
 81→			});
 82→			resizeObserver.observe(terminalEl);
 83→			resizeCleanup = (): void => resizeObserver.disconnect();
 84→		})();
 85→
 86→		return (): void => {
 87→			resizeCleanup?.();
 88→			dataCleanup?.();
 89→			termCleanup?.();
 90→		};
 91→	});
 92→
 93→	onDestroy((): void => {
 94→		ws?.close();
 95→		terminalInstance?.dispose();
 96→	});
 97→</script>
