  1→import type { IncomingMessage } from 'http';
  2→import type { Duplex } from 'stream';
  3→import { WebSocketServer, type WebSocket } from 'ws';
  4→import { TerminalSessionManager, type ClientToServerMessage } from './terminal-manager.js';
  5→import { NodePtyFactory } from './node-pty-process.js';
  6→import { getDb } from '../db/index.js';
  7→import { getSessionById } from '../db/sessions.js';
  8→import { createFeedEntry } from '../db/feed-entries.js';
  9→import { emitFeedEntry } from '../sessions/feed-emitter.js';
 10→import { randomUUID } from 'crypto';
 11→import type { FeedEntry } from '$lib/types/feed.js';
 12→import type { FeedRole } from '$lib/types/feed.js';
 13→
 14→// ---------------------------------------------------------------------------
 15→// Singletons (one per process / Vite SSR module instance)
 16→// ---------------------------------------------------------------------------
 17→
 18→let wss: WebSocketServer | null = null;
 19→let manager: TerminalSessionManager | null = null;
 20→
 21→function getWss(): WebSocketServer {
 22→	if (!wss) wss = new WebSocketServer({ noServer: true });
 23→	return wss;
 24→}
 25→
 26→function getManager(): TerminalSessionManager {
 27→	if (!manager) {
 28→		const db = getDb();
 29→		const feedHandler = {
 30→			addEntry(sessionId: string, role: string, content: string): void {
 31→				const row = createFeedEntry(db, {
 32→					id: randomUUID().replace(/-/g, ''),
 33→					session_id: sessionId,
 34→					role,
 35→					content
 36→				});
 37→				const entry: FeedEntry = {
 38→					id: row.id,
 39→					sessionId: row.session_id,
 40→					role: row.role as FeedRole,
 41→					content: row.content,
 42→					metadata: row.metadata as FeedEntry['metadata'],
 43→					ts: row.created_at
 44→				};
 45→				emitFeedEntry(sessionId, entry);
 46→			}
 47→		};
 48→		manager = new TerminalSessionManager(new NodePtyFactory(), feedHandler);
 49→	}
 50→	return manager;
 51→}
 52→
 53→// ---------------------------------------------------------------------------
 54→// URL pattern: /ws/terminal/<sessionId>
 55→// ---------------------------------------------------------------------------
 56→
 57→const WS_PATH = /^\/ws\/terminal\/([^/]+)$/;
 58→
 59→export function handleUpgrade(req: IncomingMessage, socket: Duplex, head: Buffer): void {
 60→	const url = req.url ?? '';
 61→	const match = url.match(WS_PATH);
 62→	if (!match) {
 63→		socket.destroy();
 64→		return;
 65→	}
 66→
 67→	const sessionId = match[1];
 68→
 69→	getWss().handleUpgrade(req, socket, head, (ws: WebSocket) => {
 70→		handleTerminalWebSocket(sessionId, ws);
 71→	});
 72→}
 73→
 74→export function handleTerminalWebSocket(sessionId: string, ws: WebSocket): void {
 75→	const db = getDb();
 76→	const sessionRow = getSessionById(db, sessionId);
 77→
 78→	if (!sessionRow) {
 79→		ws.close(4004, 'Session not found');
 80→		return;
 81→	}
 82→
 83→	if (sessionRow.type !== 'terminal') {
 84→		ws.close(4005, 'Session is not a terminal session');
 85→		return;
 86→	}
 87→
 88→	const mgr = getManager();
 89→
 90→	const connection = {
 91→		send(msg: { type: string; data?: string; code?: number }): void {
 92→			if (ws.readyState === ws.OPEN) {
 93→				ws.send(JSON.stringify(msg));
 94→			}
 95→		},
 96→		onMessage(handler: (msg: ClientToServerMessage) => void): void {
 97→			ws.on('message', (data: Buffer): void => {
 98→				try {
 99→					const parsed = JSON.parse(data.toString()) as ClientToServerMessage;
100→					handler(parsed);
101→				} catch {
102→					// ignore malformed messages
103→				}
104→			});
105→		},
106→		close(): void {
107→			ws.close();
108→		}
109→	};
110→
111→	mgr.connect(
112→		{
113→			sessionId,
114→			containerId: sessionRow.container_id,
115→			cols: 80,
116→			rows: 24
117→		},
118→		connection
119→	);
120→
121→	ws.on('close', (): void => {
122→		mgr.disconnect(sessionId);
123→	});
124→}
