  1→import type { PtyFactory, IPtyProcess } from './pty-service.js';
  2→
  3→// ---------------------------------------------------------------------------
  4→// Message protocol
  5→// ---------------------------------------------------------------------------
  6→
  7→export interface TerminalInputMessage {
  8→	type: 'input';
  9→	data: string;
 10→}
 11→
 12→export interface TerminalResizeMessage {
 13→	type: 'resize';
 14→	cols: number;
 15→	rows: number;
 16→}
 17→
 18→export type ClientToServerMessage = TerminalInputMessage | TerminalResizeMessage;
 19→
 20→export interface TerminalOutputMessage {
 21→	type: 'output';
 22→	data: string;
 23→}
 24→
 25→export interface TerminalExitMessage {
 26→	type: 'exit';
 27→	code: number;
 28→}
 29→
 30→export type ServerToClientMessage = TerminalOutputMessage | TerminalExitMessage;
 31→
 32→// ---------------------------------------------------------------------------
 33→// Interfaces
 34→// ---------------------------------------------------------------------------
 35→
 36→export interface TerminalConnection {
 37→	send(message: ServerToClientMessage): void;
 38→	onMessage(handler: (msg: ClientToServerMessage) => void): void;
 39→	close(): void;
 40→}
 41→
 42→export interface FeedHandler {
 43→	addEntry(sessionId: string, role: string, content: string): void;
 44→}
 45→
 46→export interface TerminalSessionConfig {
 47→	sessionId: string;
 48→	containerId: string;
 49→	cols: number;
 50→	rows: number;
 51→}
 52→
 53→// ---------------------------------------------------------------------------
 54→// ANSI stripping (minimal — removes CSI sequences and SGR codes)
 55→// ---------------------------------------------------------------------------
 56→
 57→function stripAnsi(str: string): string {
 58→	return str.replace(
 59→		// eslint-disable-next-line no-control-regex
 60→		/\x1b\[[0-9;]*[A-Za-z]|\x1b\][^\x07]*\x07|\x1b[^[]|[\x00-\x08\x0b-\x1f\x7f]/g,
 61→		''
 62→	);
 63→}
 64→
 65→// ---------------------------------------------------------------------------
 66→// Session state
 67→// ---------------------------------------------------------------------------
 68→
 69→interface SessionState {
 70→	pty: IPtyProcess;
 71→	cleanup: () => void;
 72→}
 73→
 74→// ---------------------------------------------------------------------------
 75→// Manager
 76→// ---------------------------------------------------------------------------
 77→
 78→const OUTPUT_FLUSH_MS = 500;
 79→
 80→export class TerminalSessionManager {
 81→	private sessions = new Map<string, SessionState>();
 82→
 83→	constructor(
 84→		private ptyFactory: PtyFactory,
 85→		private feedHandler: FeedHandler
 86→	) {}
 87→
 88→	connect(config: TerminalSessionConfig, connection: TerminalConnection): void {
 89→		const { sessionId, containerId, cols, rows } = config;
 90→
 91→		const pty = this.ptyFactory.spawn('docker', ['exec', '-it', containerId, '/bin/bash'], {
 92→			cols,
 93→			rows
 94→		});
 95→
 96→		let inputBuffer = '';
 97→		let outputBuffer = '';
 98→		let outputTimer: ReturnType<typeof setTimeout> | null = null;
 99→
100→		const flushOutput = (): void => {
101→			if (outputBuffer) {
102→				const stripped = stripAnsi(outputBuffer).trim();
103→				if (stripped) {
104→					this.feedHandler.addEntry(sessionId, 'output', stripped);
105→				}
106→				outputBuffer = '';
107→			}
108→		};
109→
110→		const unsubData = pty.onData((data: string): void => {
111→			connection.send({ type: 'output', data });
112→			outputBuffer += data;
113→			if (outputTimer !== null) clearTimeout(outputTimer);
114→			outputTimer = setTimeout(flushOutput, OUTPUT_FLUSH_MS);
115→		});
116→
117→		const unsubExit = pty.onExit((code: number): void => {
118→			if (outputTimer !== null) {
119→				clearTimeout(outputTimer);
120→				outputTimer = null;
121→			}
122→			flushOutput();
123→			connection.send({ type: 'exit', code });
124→			this.sessions.delete(sessionId);
125→		});
126→
127→		connection.onMessage((msg: ClientToServerMessage): void => {
128→			if (msg.type === 'input') {
129→				pty.write(msg.data);
130→
131→				// Build up input buffer; on CR/LF create a command feed entry
132→				inputBuffer += msg.data;
133→				if (msg.data.includes('\r') || msg.data.includes('\n')) {
134→					const command = inputBuffer.replace(/[\r\n]/g, '').trim();
135→					if (command) {
136→						this.feedHandler.addEntry(sessionId, 'command', command);
137→					}
138→					inputBuffer = '';
139→				}
140→			} else if (msg.type === 'resize') {
141→				pty.resize(msg.cols, msg.rows);
142→			}
143→		});
144→
145→		this.sessions.set(sessionId, {
146→			pty,
147→			cleanup: (): void => {
148→				unsubData();
149→				unsubExit();
150→				if (outputTimer !== null) clearTimeout(outputTimer);
151→				pty.kill();
152→			}
153→		});
154→	}
155→
156→	disconnect(sessionId: string): void {
157→		const session = this.sessions.get(sessionId);
158→		if (session) {
159→			session.cleanup();
160→			this.sessions.delete(sessionId);
161→		}
162→	}
163→
164→	isActive(sessionId: string): boolean {
165→		return this.sessions.has(sessionId);
166→	}
167→}
