 1→export interface PtyOptions {
 2→	cols: number;
 3→	rows: number;
 4→	cwd?: string;
 5→	env?: Record<string, string>;
 6→}
 7→
 8→export interface IPtyProcess {
 9→	readonly pid: number | null;
10→	write(data: string): void;
11→	resize(cols: number, rows: number): void;
12→	kill(): void;
13→	onData(handler: (data: string) => void): () => void;
14→	onExit(handler: (code: number) => void): () => void;
15→}
16→
17→export interface PtyFactory {
18→	spawn(command: string, args: string[], options: PtyOptions): IPtyProcess;
19→}
20→
21→// ---------------------------------------------------------------------------
22→// Fake implementations for testing
23→// ---------------------------------------------------------------------------
24→
25→export class FakePtyProcess implements IPtyProcess {
26→	readonly pid: number | null = 12345;
27→	killed = false;
28→
29→	private dataHandlers: ((data: string) => void)[] = [];
30→	private exitHandlers: ((code: number) => void)[] = [];
31→	private writtenData: string[] = [];
32→	private resizes: Array<{ cols: number; rows: number }> = [];
33→
34→	write(data: string): void {
35→		this.writtenData.push(data);
36→	}
37→
38→	resize(cols: number, rows: number): void {
39→		this.resizes.push({ cols, rows });
40→	}
41→
42→	kill(): void {
43→		this.killed = true;
44→	}
45→
46→	onData(handler: (data: string) => void): () => void {
47→		this.dataHandlers.push(handler);
48→		return () => {
49→			const i = this.dataHandlers.indexOf(handler);
50→			if (i >= 0) this.dataHandlers.splice(i, 1);
51→		};
52→	}
53→
54→	onExit(handler: (code: number) => void): () => void {
55→		this.exitHandlers.push(handler);
56→		return () => {
57→			const i = this.exitHandlers.indexOf(handler);
58→			if (i >= 0) this.exitHandlers.splice(i, 1);
59→		};
60→	}
61→
62→	// Test helpers
63→	simulateOutput(data: string): void {
64→		this.dataHandlers.forEach((h) => h(data));
65→	}
66→
67→	simulateExit(code: number): void {
68→		this.exitHandlers.forEach((h) => h(code));
69→	}
70→
71→	getWritten(): string[] {
72→		return [...this.writtenData];
73→	}
74→
75→	getLastSize(): { cols: number; rows: number } | undefined {
76→		return this.resizes[this.resizes.length - 1];
77→	}
78→}
79→
80→export class FakePtyFactory implements PtyFactory {
81→	lastCreated: FakePtyProcess | null = null;
82→	lastCommand: string | null = null;
83→	lastArgs: string[] | null = null;
84→	lastOptions: PtyOptions | null = null;
85→
86→	spawn(command: string, args: string[], options: PtyOptions): IPtyProcess {
87→		this.lastCommand = command;
88→		this.lastArgs = args;
89→		this.lastOptions = options;
90→		this.lastCreated = new FakePtyProcess();
91→		return this.lastCreated;
92→	}
93→}
