 1→import type { IPtyProcess, PtyOptions, PtyFactory } from './pty-service.js';
 2→
 3→/**
 4→ * Real PTY implementation backed by node-pty.
 5→ * Imported lazily so test environments that lack native binaries can still run.
 6→ */
 7→export class NodePtyProcess implements IPtyProcess {
 8→	// eslint-disable-next-line @typescript-eslint/no-explicit-any
 9→	private pty: any;
10→
11→	constructor(command: string, args: string[], options: PtyOptions) {
12→		// Dynamic require so the module is not resolved at import time in tests.
13→		// eslint-disable-next-line @typescript-eslint/no-require-imports
14→		const nodePty = require('node-pty') as {
15→			spawn: (
16→				file: string,
17→				args: string[],
18→				options: Record<string, unknown>
19→				// eslint-disable-next-line @typescript-eslint/no-explicit-any
20→			) => any;
21→		};
22→		this.pty = nodePty.spawn(command, args, {
23→			name: 'xterm-color',
24→			cols: options.cols,
25→			rows: options.rows,
26→			cwd: options.cwd ?? process.cwd(),
27→			env: options.env ?? (process.env as Record<string, string>)
28→		});
29→	}
30→
31→	get pid(): number | null {
32→		return this.pty.pid ?? null;
33→	}
34→
35→	write(data: string): void {
36→		this.pty.write(data);
37→	}
38→
39→	resize(cols: number, rows: number): void {
40→		this.pty.resize(cols, rows);
41→	}
42→
43→	kill(): void {
44→		this.pty.kill();
45→	}
46→
47→	onData(handler: (data: string) => void): () => void {
48→		const disposable = this.pty.onData(handler);
49→		return () => disposable.dispose();
50→	}
51→
52→	onExit(handler: (code: number) => void): () => void {
53→		const disposable = this.pty.onExit(({ exitCode }: { exitCode: number }) => handler(exitCode));
54→		return () => disposable.dispose();
55→	}
56→}
57→
58→export class NodePtyFactory implements PtyFactory {
59→	spawn(command: string, args: string[], options: PtyOptions): IPtyProcess {
60→		return new NodePtyProcess(command, args, options);
61→	}
62→}
